### Field Parsing Structure

```rust
struct ParsedField {
    ident: syn::Ident,
    ty: syn::Type,
    is_input: bool,
    is_output: bool,
    description: String,  // from doc comment
    alias: Option<String>,
    constraints: Vec<ParsedConstraint>,
}

struct ParsedConstraint {
    kind: ConstraintKind,  // Check or Assert
    expression: String,
    label: Option<String>,
}

struct ParsedSignature {
    input_fields: Vec<ParsedField>,
    output_fields: Vec<ParsedField>,
    instruction: String,  // from struct doc comment
}

fn parse_signature_fields(fields: &Punctuated<syn::Field, Comma>) -> syn::Result<ParsedSignature> {
    let mut input_fields = Vec::new();
    let mut output_fields = Vec::new();

    for field in fields {
        let parsed = parse_single_field(field)?;

        // Validate: must have exactly one of input/output
        if parsed.is_input && parsed.is_output {
            return Err(syn::Error::new_spanned(
                field,
                "field cannot be both #[input] and #[output]"
            ));
        }
        if !parsed.is_input && !parsed.is_output {
            return Err(syn::Error::new_spanned(
                field,
                "field must have #[input] or #[output] attribute"
            ));
        }

        if parsed.is_input {
            input_fields.push(parsed);
        } else {
            output_fields.push(parsed);
        }
    }

    // Validate: must have at least one input and one output
    if input_fields.is_empty() {
        return Err(syn::Error::new(
            Span::call_site(),
            "#[derive(Signature)] requires at least one #[input] field"
        ));
    }
    if output_fields.is_empty() {
        return Err(syn::Error::new(
            Span::call_site(),
            "#[derive(Signature)] requires at least one #[output] field"
        ));
    }

    Ok(ParsedSignature { input_fields, output_fields, instruction: String::new() })
}
