## Attribute Parsing

```rust
fn parse_single_field(field: &syn::Field) -> syn::Result<ParsedField> {
    let mut is_input = false;
    let mut is_output = false;
    let mut alias = None;
    let mut constraints = Vec::new();
    let mut description = String::new();

    for attr in &field.attrs {
        if attr.path().is_ident("input") {
            is_input = true;
        } else if attr.path().is_ident("output") {
            is_output = true;
        } else if attr.path().is_ident("alias") {
            alias = Some(parse_string_attr(attr)?);
        } else if attr.path().is_ident("check") {
            constraints.push(parse_constraint_attr(attr, ConstraintKind::Check)?);
        } else if attr.path().is_ident("assert") {
            constraints.push(parse_constraint_attr(attr, ConstraintKind::Assert)?);
        } else if attr.path().is_ident("doc") {
            // Extract doc comment
            if let Some(doc) = extract_doc_comment(attr) {
                if !description.is_empty() {
                    description.push(' ');
                }
                description.push_str(&doc);
            }
        }
    }

    Ok(ParsedField {
        ident: field.ident.clone().unwrap(),
        ty: field.ty.clone(),
        is_input,
        is_output,
        description,
        alias,
        constraints,
    })
}
