fn parse_constraint_attr(attr: &Attribute, kind: ConstraintKind) -> syn::Result<ParsedConstraint> {
    // Parse: #[check("expr", label = "name")] or #[assert("expr")]
    let args: ConstraintArgs = attr.parse_args()?;

    // Check must have label
    if kind == ConstraintKind::Check && args.label.is_none() {
        return Err(syn::Error::new_spanned(
            attr,
            "#[check] requires a label: #[check(\"expr\", label = \"name\")]"
        ));
    }

    Ok(ParsedConstraint {
        kind,
        expression: args.expression,
        label: args.label,
    })
}
